// ===== STORAGE (localStorage for deploy, swap to Turso API later) =====
const store = {
  async get(k) { try { const v = localStorage.getItem("cl_"+k); return v ? JSON.parse(v) : null; } catch { return null; } },
  async set(k, v) { try { localStorage.setItem("cl_"+k, JSON.stringify(v)); } catch(e) { console.error(e); } },
};

