const INIT_NOTES = [
 {id:"n1",sectionId:"s420",title:"สรุปละเมิด ม.420 — องค์ประกอบ 4 ข้อ + ตัวอย่างคำพิพากษา",content:"## ละเมิดตาม ม.420\n\n### องค์ประกอบ 4 ประการ:\n1. **จงใจหรือประมาทเลินเล่อ**\n   - จงใจ = รู้สำนึก + ประสงค์ต่อผล\n   - ประมาท = ไม่ใช้ความระมัดระวังตามสมควร\n\n2. **ทำต่อบุคคลอื่นโดยผิดกฎหมาย**\n   - ผิดกฎหมาย = ฝ่าฝืนข้อห้าม/ไม่ทำตามหน้าที่\n\n3. **ให้เขาเสียหาย**\n   - ชีวิต ร่างกาย อนามัย เสรีภาพ ทรัพย์สิน สิทธิ\n\n4. **มีความสัมพันธ์ระหว่างเหตุกับผล**\n   - ถ้าไม่กระทำ ผลก็จะไม่เกิด\n\n### เชื่อมโยง\n- ม.421 — ใช้สิทธิเพื่อให้เกิดเสียหาย = มิชอบ\n- ม.425 — นายจ้างรับผิดร่วม\n- ม.438 — ค่าสินไหมทดแทน",source:"lecture อ.สมชาย",type:"summary",starred:true,updatedAt:"2025-03-01"},
 {id:"n2",sectionId:"s172",title:"เปรียบเทียบ โมฆะ vs โมฆียะ — ตารางสรุป",content:"## โมฆะ vs โมฆียะ\n\n### โมฆะ (ม.172-173)\n- **ผล**: เสียเปล่ามาแต่ต้น\n- **ใครอ้าง**: ผู้มีส่วนได้เสียคนใดก็ได้\n- **ให้สัตยาบัน**: ไม่ได้\n- **สาเหตุ**: วัตถุประสงค์ต้องห้าม (ม.150) / ผิดแบบ (ม.152) / สำคัญผิดสาระสำคัญ (ม.156) / เจตนาลวง (ม.155)\n\n### โมฆียะ (ม.175-181)\n- **ผล**: สมบูรณ์จนกว่าจะถูกบอกล้าง\n- **ใครอ้าง**: เฉพาะผู้มีสิทธิบอกล้าง\n- **ให้สัตยาบัน**: ได้ → สมบูรณ์ตลอดไป\n- **สาเหตุ**: ความสามารถบกพร่อง (ม.153) / กลฉ้อฉล (ม.159) / ข่มขู่ (ม.164) / สำคัญผิดในคุณสมบัติ (ม.157)\n\n### อายุความบอกล้าง (ม.181)\n- **1 ปี** นับแต่รู้มูลเหตุ\n- **10 ปี** นับแต่วันทำนิติกรรม",source:"เปรียบเทียบเอง",type:"comparison",starred:true,updatedAt:"2025-03-05"},
 {id:"n3",sectionId:"s7",title:"สรุปดอกเบี้ย — ม.7 (3%) vs ม.224 (5%) แก้ไข พ.ศ.2564",content:"## ดอกเบี้ยตามกฎหมายแพ่ง\n\n### ม.7 อัตราดอกเบี้ยตามกฎหมาย\n- **เดิม**: ร้อยละ 7.5 ต่อปี\n- **แก้ไข พ.ศ.2564**: ร้อยละ **3** ต่อปี\n- ใช้เมื่อ: ไม่ได้กำหนดอัตราดอกเบี้ยไว้\n\n### ม.224 อัตราดอกเบี้ยผิดนัด\n- **เดิม**: ร้อยละ 7.5 ต่อปี\n- **แก้ไข พ.ศ.2564**: ร้อยละ **5** ต่อปี\n- ใช้เมื่อ: ลูกหนี้ผิดนัดชำระหนี้เงิน\n\n### ข้อสังเกต\n- ดอกเบี้ยผิดนัด (5%) > ดอกเบี้ยปกติ (3%) → เป็นบทลงโทษ\n- ทบทวนทุก 3 ปีโดย พ.ร.ฎ.",source:"สรุปจากการแก้ไข พ.ร.บ. แก้ไข ป.พ.พ. พ.ศ.2564",type:"summary",starred:true,updatedAt:"2025-03-10"},
];

